    }

    // MARK: - Helpers

    /// Transitions the flow to the given step with a spring animation.
    private func advance(to nextStep: ReturnStep) {
        withAnimation(.spring(duration: 0.4)) {
            step = nextStep
        }
    }

    /// Simulates a staggered AI analysis: policy check → photo review → quality assessment → verdict.
    private func runAIAnalysis() {
        isAnalyzing = true
        aiStep1Done = false
        aiStep2Done = false
        aiStep3Done = false
        Task {
            // Staggered checklist: each step appears sequentially
            try? await Task.sleep(for: .seconds(0.6))
            await MainActor.run { aiStep1Done = true }

            try? await Task.sleep(for: .seconds(0.7))
            await MainActor.run { aiStep2Done = true }

            try? await Task.sleep(for: .seconds(0.9))
            await MainActor.run { aiStep3Done = true }

            try? await Task.sleep(for: .seconds(0.6))
            await MainActor.run {
                withAnimation(.spring(duration: 0.5)) {
                    isAnalyzing = false
                    aiResult = AIVerdict(
                        isEligible: true,
                        title: "Return Approved",
                        message: "This item meets our return policy. The product is within the 30-day return window and photo confirms acceptable condition.",
                        icon: "checkmark.shield.fill",
                        color: .green,
                        conditionLabel: "Good ✓",
                        eligibilityLabel: "Approved ✓"
                    )
                }
            }
        }
    }
}

// MARK: - Camera Picker (UIKit Bridge)

/// UIKit bridge that presents the device camera for photo capture.
private struct CameraPickerView: UIViewControllerRepresentable {
    /// Callback invoked with the captured image.
    let onCapture: (UIImage) -> Void

    /// Creates and configures a `UIImagePickerController` set to the camera source.
    func makeUIViewController(context: Context) -> UIImagePickerController {
        let picker = UIImagePickerController()
        if UIImagePickerController.isSourceTypeAvailable(.camera) {
            picker.sourceType = .camera
        }
        picker.delegate = context.coordinator
        return picker
    }

    /// No-op; updates are not needed for the camera picker.
    func updateUIViewController(_ uiViewController: UIImagePickerController, context: Context) {}

    /// Creates the coordinator that handles delegate callbacks from the picker.
    func makeCoordinator() -> Coordinator { Coordinator(onCapture: onCapture) }

    /// Coordinator that bridges `UIImagePickerControllerDelegate` events to SwiftUI.
    class Coordinator: NSObject, UINavigationControllerDelegate, UIImagePickerControllerDelegate {
        /// Callback to invoke when an image is captured.
        let onCapture: (UIImage) -> Void
        /// Initializes the coordinator with a capture callback.
        init(onCapture: @escaping (UIImage) -> Void) { self.onCapture = onCapture }

        /// Called when the user picks or captures an image; forwards it via `onCapture`.
        func imagePickerController(_ picker: UIImagePickerController, didFinishPickingMediaWithInfo info: [UIImagePickerController.InfoKey: Any]) {
            if let image = info[.originalImage] as? UIImage {
                onCapture(image)
            }
            picker.dismiss(animated: true)
        }

        /// Called when the user cancels the picker; dismisses the controller.
        func imagePickerControllerDidCancel(_ picker: UIImagePickerController) {
            picker.dismiss(animated: true)
        }
    }
}

// MARK: - Supporting Types

/// The sequential steps in the return flow.
private enum ReturnStep: Hashable {
    case orderConfirm
    case returnReason
    case photoCapture
    case aiCheck
    case resolution
    case confirmation
}

/// Reasons a customer may want to return an item.
private enum ReturnReason: String, CaseIterable, Identifiable {
    case wrongSize = "wrong_size"
    case defective = "defective"
    case notAsDescribed = "not_as_described"
    case changedMind = "changed_mind"
    case arrivedLate = "arrived_late"

    /// Unique identifier derived from the raw value.
    var id: String { rawValue }

    /// Human-readable label describing the return reason.
    var label: String {
        switch self {
        case .wrongSize: return "Wrong size or fit"
        case .defective: return "Defective or damaged"
        case .notAsDescribed: return "Not as described"
        case .changedMind: return "Changed my mind"
        case .arrivedLate: return "Arrived too late"
        }
    }

    /// SF Symbol icon name representing this return reason.
    var icon: String {
        switch self {
        case .wrongSize: return "ruler"
        case .defective: return "exclamationmark.triangle.fill"
        case .notAsDescribed: return "eye.slash.fill"
        case .changedMind: return "arrow.uturn.left"
        case .arrivedLate: return "clock.badge.exclamationmark"
        }
    }
}

/// Available resolution options for an approved return.
private enum Resolution: String, CaseIterable, Identifiable {
    case fullRefund = "refund"
    case exchange = "exchange"
    case storeCredit = "credit"

    /// Unique identifier derived from the raw value.
    var id: String { rawValue }

    /// Display title for this resolution option.
    var title: String {
        switch self {
        case .fullRefund: return "Full Refund"
        case .exchange: return "Exchange"
        case .storeCredit: return "Store Credit"
        }
    }

    /// SF Symbol icon name representing this resolution.
    var icon: String {
        switch self {
        case .fullRefund: return "dollarsign.arrow.circlepath"
        case .exchange: return "arrow.triangle.2.circlepath"
        case .storeCredit: return "creditcard.fill"
        }
    }

    /// Returns a subtitle describing the financial outcome for the given item price.
    func subtitle(for price: Double) -> String {
        let formatted = String(format: "$%.2f", price)
        switch self {
        case .fullRefund: return "\(formatted) back to original payment"
        case .exchange: return "Pick a new size or color"
        case .storeCredit: return "\(String(format: "$%.2f", price * 1.10)) credit (+10% bonus)"
        }
    }

    /// Returns a short label with the formatted amount for the return summary card.
    func amountLabel(for price: Double) -> String {
        switch self {
        case .fullRefund: return String(format: "$%.2f refund", price)
        case .exchange: return "Even exchange"
        case .storeCredit: return String(format: "$%.2f credit", price * 1.10)
        }
    }
}

/// The result of the simulated AI return-policy analysis.
private struct AIVerdict {
    /// Whether the return was approved by the AI analysis.
    let isEligible: Bool
    /// Headline text for the verdict (e.g. "Return Approved").
    let title: String
    /// Detailed explanation of the verdict.
    let message: String
    /// SF Symbol icon name for the verdict badge.
    let icon: String
    /// Color used for the verdict icon and highlights.
    let color: Color
    /// Short label summarizing the item condition.
    let conditionLabel: String
    /// Short label summarizing eligibility status.
    let eligibilityLabel: String
}

